import { EditCalendar, GridOn as GridOnIcon } from '@mui/icons-material';
import {
  Box,
  Button,
  Card,
  Container,
  FormControl,
  Grid2 as Grid,
  IconButton,
  MenuItem,
  Select,
  Stack,
  Typography,
} from '@mui/material';
import _ from 'lodash';
import React, {
  ReactElement,
  useEffect,
  useMemo,
  useState,
} from 'react';

import CriticalError from '@/components/common/critical-error';
import { FloatingButton } from '@/components/common/floating-button';
import { ConfirmationModal } from '@/components/modal/confirmation-modal';
import { FileUploadModal } from '@/components/modal/session/file-upload-modal';
import { ScatterModal } from '@/components/modal/session/scatter-modal';
import { SessionUpdateModal } from '@/components/modal/session/session-update-modal';
import {
  CommonPagination,
  CommonPaginationData,
} from '@/components/pagination/common-pagination';
import { ResourceSearchResultTable } from '@/components/resource/resource-search-result-table';
import { SessionInfoHeader } from '@/components/sessions/session-info-header';
import { TeamPlanLimitBand } from '@/components/sessions/team-plan-limit-band';
import AppConstants, {
  AppDefaultSelectOptions,
  RESOURCE_STATUSES,
} from '@/constants/app.constants';
import { EnvManager } from '@/constants/env.constants';
import { PAGE_INFO } from '@/constants/page.constants';
import useServicesHook from '@/hooks';
import ConsoleLayout from '@/layouts/console.layout';
import { Resource } from '@/models/resource';
import { Session } from '@/models/session';
import { Team, TeamType } from '@/models/team';
import { User } from '@/models/user';
import { ServiceError } from '@/services/errors/service-error';
import {
  ResourceDateFilterType,
  resourceDefaultDateOptions,
  ResourceSortType,
  resourceSortTypes,
} from '@/services/interfaces/resources-api.interface';
import { useSelector } from '@/store';
import { checkAnalysisAvailability } from '@/utils/analysis.util';
import { wrapForLoading } from '@/utils/functions/transformer';
import { translate } from '@/utils/i18n';
import { logger } from '@/utils/logger';
import { PathUtil } from '@/utils/path.util';

type SessionDetailPageMode = 'upload';

type ResourceQueryCondition = {
  keyword: string;
  sort: ResourceSortType;
  filter: ResourceDateFilterType;
  searchTrigger: Date;
};

const NO_OP = () => {
  // No Operation
};

const defaultCondition: ResourceQueryCondition & CommonPaginationData = {
  keyword: '',
  sort: 'recent',
  filter: 'all',
  currentPage: 0,
  rowsPerPage: 10,

  searchTrigger: new Date(),
};

const buildQueryParam = (
  data: ResourceQueryCondition & CommonPaginationData,
) => {
  return {
    keyword: data.keyword.toString(),
    sort: data.sort.toString(),
    filter: data.filter.toString(),
    page: data.currentPage.toString(),
    pageSize: data.rowsPerPage.toString(),
  };
};

const parseQueryParam = (data: any) => {
  return _.chain({
    keyword: PathUtil.getStringFromQuery(data.keyword),
    sort: PathUtil.getEnumFromQuery(resourceSortTypes, data.sort),
    filter: PathUtil.getEnumFromQuery(resourceDefaultDateOptions, data.filter),
    currentPage: PathUtil.getIntFromQuery(data.page),
    rowsPerPage: PathUtil.getIntFromQuery(data.pageSize),
  })
    .omitBy((v, __) => {
      return _.isNil(v);
    })
    .defaultsDeep(defaultCondition)
    .value();
};

function PageInner({
  currentUser,
  currentTeam,
  sessionId,
  mode,
}: {
  currentUser: User;
  currentTeam: Team;
  sessionId: string;
  mode: SessionDetailPageMode | null;
}) {
  const { router, services } = useServicesHook();
  const unit = useSelector((state) => state.user.unit);

  const teamId = currentTeam.id;

  const [isInitialized, setIsInitialized] = useState<boolean>(false);
  const [loadError, setLoadError] = useState<ServiceError | null>(null);
  const [pageShownDate, _] = useState<Date>(new Date());
  const [session, setSession] = useState<Session>();
  const [resources, setResources] = useState<Resource[]>([]);
  const [conditions, setConditions] = useState<
    ResourceQueryCondition & CommonPaginationData
  >({
    ...defaultCondition,
    ...parseQueryParam(router.query),
    ...services.localStorage.defaultPaginationData(
      currentUser.id,
      router.query,
    ),
  });
  const [numberOfTotalItems, setNumberOfTotalItems] = useState<number>(0);
  const [isEditingSession, setIsEditingSession] = useState<boolean>(false);
  const [isCsvDownloading, setIsCsvDownloading] = useState<boolean>(false);

  // confirmation modal
  const [isOpenDeleteResourceModal, setIsOpenDeleteResourceModal] =
    useState<boolean>(false);
  const [deleteResourceModalData, setDeleteResourceModalData] = useState<{
    onClose: Function;
    cbOk: Function;
  }>({
    onClose: NO_OP,
    cbOk: NO_OP,
  });

  const [isOpenReanalyzeResourceModal, setIsOpenReanalyzeResourceModal] =
    useState<boolean>(false);
  const [reanalyzeResourceModalData, setReanalyzeResourceModalData] = useState<{
    onClose: Function;
    cbOk: Function;
  }>({
    onClose: NO_OP,
    cbOk: NO_OP,
  });

  const [isScatterModalOpen, setIsScatterModalOpen] = useState<boolean>(false);

  const dateFilterOptions = AppDefaultSelectOptions.dateFilter;

  const sortOptions = useMemo((): {
    name: string;
    value: ResourceSortType;
  }[] => {
    return [
      {
        name: translate('order_newest_first'),
        value: 'recent',
      },
      {
        name: translate('order_oldest_first'),
        value: 'oldest',
      },
      {
        name: translate('order_recorded_at_newest_first'),
        value: 'recentRecorded',
      },
      {
        name: translate('order_recorded_at_oldest_first'),
        value: 'oldestRecorded',
      },
      {
        name: translate('order_filename'),
        value: 'filename',
      },
      {
        name: translate('order_filename_desc'),
        value: 'filenameDesc',
      },
      // {
      //   name: 'Most viewed',
      //   value: 'view_count',
      // }
    ];
  }, []);

  const analysisAvailability = session
    ? checkAnalysisAvailability(session, currentUser, currentTeam)
    : null;

  const hasCrossAccessInTeam = User.isAccessible(
    currentUser,
    teamId,
    'basic',
    'read',
    true,
  );


  // シングルユーザーチームでは動画のアップロード、CSV のダウンロードの導線を非表示にする
  // 開発用に dev では表示したままにする
  // https://knowhere-org.slack.com/archives/C03EGR0M9AN/p1759381143908219
  const isStagingOrProductionSingleTeam =
    (EnvManager.config.APP_ENV === 'staging' ||
      EnvManager.config.APP_ENV === 'production') &&
    currentTeam.teamType === TeamType.SINGLE;

  const [isFileUploadModalOpen, setIsFileUploadModalOpen] = useState<boolean>(
    mode == 'upload',
  );

  const getSession = async (sessionId: string) => {
    const result = await services.default.session.getSession(teamId, sessionId);
    if (result.error) {
      setLoadError(result.error);
      return;
    }
    setLoadError(null);
    setSession(result.session);
  };

  const getResourcesAndUpdateList = async (sessionId: string) => {
    const result = await services.default.resource.getResources(
      teamId,
      sessionId,
      {
        keyword: conditions.keyword,
        sort: conditions.sort,
        dateFilter: conditions.filter,
        offset: conditions.currentPage * conditions.rowsPerPage,
        pageSize: conditions.rowsPerPage,
        userId: hasCrossAccessInTeam ? null : currentUser.id,
      },
    );
    if (result.error) {
      // TODO
      return;
    }
    setResources(result.resources);
    setNumberOfTotalItems(result.total);
  };

  const downloadAsCsv = async () => {
    wrapForLoading(setIsCsvDownloading, () => {
      services.default.resource.downloadResourcesAsCsv(
        teamId,
        sessionId,
        {
          keyword: conditions.keyword,
          sort: conditions.sort,
          dateFilter: conditions.filter,
          unit: unit == 'cm' ? 'm' : 'inch',
          userId: hasCrossAccessInTeam ? null : currentUser.id,
        },
      );
    });
  };

  const onDeleteButtonClicked = async (res: Resource) => {
    setIsOpenDeleteResourceModal(true);
    setDeleteResourceModalData({
      cbOk: async () => {
        await services.default.resource.deleteResource(
          teamId,
          sessionId,
          res.id,
        );
        getResourcesAndUpdateList(sessionId);
      },
      onClose: () => {
        setIsOpenDeleteResourceModal(false);
        setDeleteResourceModalData({
          onClose: NO_OP,
          cbOk: NO_OP,
        });
      },
    });
  };

  const onReanalyzeButtonClicked = async (res: Resource) => {
    setIsOpenReanalyzeResourceModal(true);
    setReanalyzeResourceModalData({
      cbOk: async () => {
        await services.default.resource.reAnalyze(teamId, sessionId, res.id);
        getResourcesAndUpdateList(sessionId);
      },
      onClose: () => {
        setIsOpenReanalyzeResourceModal(false);
        setReanalyzeResourceModalData({
          onClose: NO_OP,
          cbOk: NO_OP,
        });
      },
    });
  };

  const initialize = async () => {
    try {
      await Promise.all([getSession(sessionId)]);
      const parsed = {
        ...parseQueryParam(router.query),
        ...services.localStorage.defaultPaginationData(
          currentUser.id,
          router.query,
        ),
      };
      setConditions({
        ...conditions,
        ...parsed,
      });
      updateQueryParameters({
        ...parsed,
        searchTrigger: new Date(),
      });
    } finally {
      setIsInitialized(true);
    }
  };

  const updateQueryParameters = (
    conds: ResourceQueryCondition & CommonPaginationData,
    forceReplace = false,
  ) => {
    const param = buildQueryParam(conds);
    const pathWithQuery = PAGE_INFO.SESSION_RESOURCES.href(
      teamId,
      sessionId,
      param,
    );
    if (forceReplace) {
      router.replace(pathWithQuery);
      return;
    }
    PathUtil.routerPushOrReplaceWithPaginationData(
      router,
      conds.currentPage,
      pathWithQuery,
    );
  };

  useEffect(() => {
    initialize();
  }, []);

  // This must be configured for browser back.
  useEffect(() => {
    if (!isInitialized) {
      return;
    }
    // Important: Call after setConditions to trigger (*1)
    const parsed = parseQueryParam(router.query);
    setConditions({
      ...conditions,
      ...parsed,
      searchTrigger: new Date(),
    });
  }, [router.query]); // browser back -> trigger by paginationData

  useEffect(() => {
    if (!isInitialized) {
      return;
    }
    getSession(sessionId);
    getResourcesAndUpdateList(sessionId);
  }, [sessionId, conditions.searchTrigger]); // reset

  useEffect(() => {
    const setIntervalFunctionId = setInterval(() => {
      logger.debug(`Checking uploaded resources for status...`);
      if (document.hidden) {
        // logger.debug(`Document is hidden`)
        return;
      }

      if (
        resources.filter(
          (resource) =>
            !RESOURCE_STATUSES.ready.value.includes(resource.status),
        ).length > 0
      ) {
        getResourcesAndUpdateList(sessionId);
      }
    }, AppConstants.RESOURCE_CHECKING_POLLING_INTERVAL);
    return () => clearInterval(setIntervalFunctionId);
  }, [resources]);

  if (!session || loadError) {
    return <CriticalError error={loadError} />;
  }

  return (
    // mbはFABのため
    <Container sx={{ position: 'relative', mb: 10 }}>
      {/* Delete Resource Modal */}
      <ConfirmationModal
        title={translate('delete_video')}
        isDeleteMode={true}
        isOpen={isOpenDeleteResourceModal}
        setIsOpen={setIsOpenDeleteResourceModal}
        onClose={deleteResourceModalData.onClose}
        cbOk={deleteResourceModalData.cbOk}
      />
      <ConfirmationModal
        title={translate('reanalyze_video')}
        isOpen={isOpenReanalyzeResourceModal}
        setIsOpen={setIsOpenReanalyzeResourceModal}
        onClose={reanalyzeResourceModalData.onClose}
        cbOk={reanalyzeResourceModalData.cbOk}
      />
      <SessionUpdateModal
        teamId={teamId}
        isOpen={isEditingSession}
        setIsOpen={setIsEditingSession}
        session={session}
        onClose={() => {
          setIsEditingSession(false);
          getSession(sessionId);
        }}
      />
      <FileUploadModal
        startingDate={pageShownDate}
        session={session}
        isOpen={isFileUploadModalOpen}
        setIsOpen={setIsFileUploadModalOpen}
        onVideoUploaded={async () => {
          getResourcesAndUpdateList(sessionId);
          setIsFileUploadModalOpen(false);
        }}
      />
      <ScatterModal
        title={translate('scatter_graph_of_breaks')}
        isOpen={isScatterModalOpen}
        setIsOpen={setIsScatterModalOpen}
        onClose={() => {
          setIsScatterModalOpen(false);
        }}
        teamId={teamId}
        sessionId={session.id}
        userId={hasCrossAccessInTeam ? null : currentUser.id}
      />
      <SessionInfoHeader
        user={currentUser}
        teamId={teamId}
        title={session.title ?? 'NO TITLE'}
        session={session}
        onClickEditButton={() => {
          setIsEditingSession(true);
        }}
        breadCrumbs={[
          {
            name: translate(PAGE_INFO.SESSIONS.name as keyof typeof translate),
            link: PAGE_INFO.SESSIONS.href(teamId),
          },
          {
            name: session.title ?? '-',
            link: PAGE_INFO.SESSION_RESOURCES.href(teamId, sessionId),
          },
        ]}
      />

      <Box sx={{ my: 3 }}>
        <TeamPlanLimitBand team={currentTeam} />
      </Box>

      <Card sx={{ backgroundColor: 'white', p: 2 }}>
        <form
          onSubmit={(e) => {
            e.preventDefault();
            getResourcesAndUpdateList(sessionId);
          }}
        >
          <Stack direction="row" spacing={2} justifyContent="space-between">
            <Grid container direction="row" spacing={1} sx={{ flex: 1 }}>
              <Grid size="auto">
                <FormControl size="small" variant="standard">
                  <Select
                    value={conditions.sort}
                    onChange={(e) => {
                      const newData = {
                        ...conditions,
                        sort: e.target.value as ResourceSortType,
                        currentPage: 0,
                      };
                      setConditions(newData);
                      updateQueryParameters(newData);
                    }}
                  >
                    {sortOptions.map((x) => {
                      return (
                        <MenuItem key={x.value} value={x.value}>
                          {translate(x.name as keyof typeof translate)}
                        </MenuItem>
                      );
                    })}
                  </Select>
                </FormControl>
              </Grid>
              <Grid size="auto">
                <FormControl size="small" variant="standard">
                  <Select
                    value={conditions.filter}
                    onChange={(e) => {
                      const newData = {
                        ...conditions,
                        filter: e.target.value as ResourceDateFilterType,
                        currentPage: 0,
                      };
                      setConditions(newData);
                      updateQueryParameters(newData);
                    }}
                  >
                    {dateFilterOptions.map((x) => {
                      return (
                        <MenuItem key={x.value} value={x.value}>
                          {translate(x.name as keyof typeof translate)}
                        </MenuItem>
                      );
                    })}
                  </Select>
                </FormControl>
              </Grid>
            </Grid>
            <Stack
              direction="row"
              spacing={1}
              alignItems="center"
              onClick={() => {
                setIsScatterModalOpen(true);
              }}
              sx={{ cursor: 'pointer' }}
            >
              <Typography variant="caption">{translate('scatter')}</Typography>
              <IconButton>
                <GridOnIcon fontSize="medium" />
              </IconButton>
            </Stack>
          </Stack>
        </form>
        <ResourceSearchResultTable
          user={currentUser}
          team={currentTeam}
          resources={resources}
          onDeleteButtonClicked={onDeleteButtonClicked}
          onReanalyzeButtonClicked={onReanalyzeButtonClicked}
          resourceSortType={conditions.sort}
        />
        {!isStagingOrProductionSingleTeam && (
          <Box display="flex" justifyContent="flex-end" sx={{ mr: 1 }}>
            <Button
              loading={isCsvDownloading}
              variant="contained"
              onClick={() => downloadAsCsv()}
            >
              {translate('download_csv')}
            </Button>
          </Box>
        )}
        <CommonPagination
          user={currentUser}
          numberOfTotalItems={numberOfTotalItems}
          commonPaginationData={{
            currentPage: conditions.currentPage,
            rowsPerPage: conditions.rowsPerPage,
          }}
          onChange={(data) => {
            updateQueryParameters({
              ...conditions,
              ...data,
            });
          }}
        />
      </Card>
      {currentUser.hasBasicWriteAccessFor(session) &&
        !isStagingOrProductionSingleTeam && (
          <FloatingButton
            icon={<EditCalendar />}
            title={translate('upload_new_video')}
            tooltipTitle={analysisAvailability?.unavailableReason}
            disabled={!analysisAvailability?.isAvailable}
            onClick={() => setIsFileUploadModalOpen(true)}
          />
        )}
    </Container>
  );
}

export default function Page() {
  const { router } = useServicesHook();

  const currentUser = useSelector((state) => state.user.me);
  const teams = useSelector((state) => state.user.accessibleTeams);
  const [team, setTeam] = useState<Team>();
  const sessionId = router.query.session_id?.toString();
  const modes: SessionDetailPageMode[] = ['upload'];
  const mode: SessionDetailPageMode | null = _.includes(
    modes,
    router.query.mode,
  )
    ? (router.query.mode as SessionDetailPageMode)
    : null;

  const teamId = router.query.team_id?.toString();

  useEffect(() => {
    if (!teamId) {
      return;
    }
    setTeam(teams.find((x) => x.id == teamId));
  }, [teamId, teams]);

  return (
    currentUser &&
    team &&
    sessionId && (
      <PageInner
        currentUser={currentUser}
        currentTeam={team}
        sessionId={sessionId}
        mode={mode}
      />
    )
  );
}

Page.getLayout = function getLayout(page: ReactElement) {
  return <ConsoleLayout>{page}</ConsoleLayout>;
};

