  const { services, reloader, dispatch } = useServicesHook();
  const teams = useSelector((state) => state.user.accessibleTeams);
  const [loadError, setLoadError] = useState<ServiceError | null>(null);
  const [isSubmitting, setIsSubmitting] = useState<boolean>(false);
  const [currentLang, setCurrentLang] =
    useState<SupportedLanguage>(getDefaultLanguage());
  const [currentUnit, setCurrentUnit] =
    useState<SupportedUnit>(getDefaultUnit());

  const isSmallScreen = useMediaQuery('(max-width:600px)', { noSsr: true });
  const contactFormUrl = useMemo(
    () => resolveContactFormUrl(currentLang, currentUser, currentTeam),
    [currentLang, currentTeam, currentUser],
  );
  const showContactFormButton = EnvManager.config.APP_ENV !== 'production';

  const searchParams = useSearchParams();
  const [tabValue, setTabValue] = useState<string>(
    searchParams.get('tab') ?? AccountTab,
  );

  const hasSuperUserReadAccess = User.isAccessible(
    currentUser,
    'all',
    'basic',
    'read',
    false,
  );

  const tabs = [AccountTab, TeamTab, ChangePasswordTab] as TranslationKey[];

  const handleTabChange = (_: React.SyntheticEvent, newValue: string) => {
    setTabValue(newValue);
  };

  const logout = () => {
    wrapForLoading(setIsSubmitting, async () => {
      await services.default.auth.signOut();
      location.href = PAGE_INFO.SIGN_IN.href();
    });
  };

  const handlePaymentSuccess = async () => {
    const status = searchParams.get('status');
    if (status === 'error') {
      enqueueSnackbar({
        variant: 'error',
        message: translate('payment_session_error'),
      });
    } else if (status === 'success') {
      enqueueSnackbar({
        variant: 'success',
        message: translate('payment_session_success'),
      });
      // チームプラン情報を更新
      await getUserInfo();
    }

    // Remove query parameters from URL
    const url = new URL(window.location.href);
    url.searchParams.delete('status');
    url.searchParams.delete('session_id');
    window.history.replaceState({}, '', url.toString());
  };

  const handleBillingPortal = async () => {
    setIsSubmitting(true);
    try {
      const result = await services.default.payment.createBillingPortalSession({
        teamId: currentTeam.id,
      });

      if (result.error) {
        throw result.error;
      }

      if (result.data?.url) {
        window.open(result.data.url, '_blank', 'noopener,noreferrer');
      }
    } catch (error) {
      enqueueSnackbar({
        variant: 'error',
        message: translate('payment_error_occurred'),
      });
    } finally {
      setIsSubmitting(false);
    }
  };

  const getUserInfo = async () => {
    const userResult = await services.default.user.getMe();
    if (userResult.error) {
      setLoadError(userResult.error);
      return;
    }

    let teams = userResult.user.teams;
    if (hasSuperUserReadAccess) {
      const teamsResult = await services.default.superAdmin.getTeams({});
      if (!teamsResult.error) {
        teams = teamsResult.teams;
      } else {
        enqueueSnackbar({
          variant: 'error',
          message: sprintf(
            '%s: %s',
            translate('snackbar_failed_to_get_accessible_teams'),
            teamsResult.error.message,
          ),
        });
      }
    }
    setLoadError(null);
    // Update plan info bound by the team.
    dispatch(
      userDataActions.setTeams({
        teams,
      }),
    );
  };

  useEffect(() => {
    reloader.reloadIfNeeded();
    setCurrentUnit(
      services.localStorage.getUnit(currentUser.id) ?? getDefaultUnit(),
    );
    setCurrentLang(
      services.localStorage.getLanguage(currentUser.id) ?? getDefaultLanguage(),
    );
    handlePaymentSuccess();
    getUserInfo();
  }, []);

  return (
    <Container>
      <Stack direction="column">
        <Box>
          <Stack direction="row" alignItems="center" sx={{ py: 1 }}>
            <ImageOrAvatar
              url={currentUser.profile?.presignedImageUrl}
              width={120}
              height={120}
            />
            <Box sx={{ flex: 1, px: 3 }}>
              <Typography variant="h1">
                {currentUser.profile?.username ?? '(No Name)'}
              </Typography>
            </Box>
            <Box>
              <Button
                color="neutral"
                loading={isSubmitting}
                onClick={() => logout()}
              >
                {translate('sign_out')}
              </Button>
            </Box>
          </Stack>
          <Divider sx={{ mt: 2 }} />
        </Box>
        <Tabs sx={{ mb: 2, mt: 4 }} value={tabValue} onChange={handleTabChange}>
          {tabs.map((tab) => {
            return (
              <Tab
                key={tab}
                label={translate(tab)}
                style={{ backgroundColor: 'inherit' }}
                sx={{ px: 2, py: 1 }}
                value={tab}
              />
            );
          })}
        </Tabs>
        {loadError ? (
          <CriticalError error={loadError} />
        ) : (
          <>
            <TabPanel index={AccountTab} value={tabValue}>
              <Paper
                sx={{
                  p: 3,
                  position: 'relative',
                  overflowWrap: 'break-word',
                }}
              >
                <IconButton
                  color="primary"
                  href={PAGE_INFO.ACCOUNT_EDIT.href(AccountTab)}
                  sx={{ position: 'absolute', top: 20, right: 20 }}
                >
                  <Edit />
                </IconButton>
                <Stack direction="column">
                  <Typography sx={{ mb: 3 }} variant="h2">
                    {translate('account')}
                  </Typography>
                  <Grid container spacing={3}>
                    <Grid size={{ sm: 6, xs: 12 }}>
                      <FormControl fullWidth sx={{ mb: 2 }}>
                        <FormLabel>
                          <Typography variant="h4">
                            {translate('email')}
                          </Typography>
                        </FormLabel>
                        <Typography>{currentUser.email}</Typography>
                      </FormControl>
                    </Grid>
                    <Grid size={{ sm: 6, xs: 12 }}>
                      <FormControl fullWidth sx={{ mb: 2 }}>
                        <FormLabel>
                          <Typography variant="h4">
                            {translate('language')}
                          </Typography>
                        </FormLabel>
                        <Typography>
                          {
                            _.find(
                              SUPPORTED_LANGUAGES,
                              (x) => x.value == currentLang,
                            )?.name
                          }
                        </Typography>
                      </FormControl>
                      <FormControl fullWidth sx={{ mb: 2 }}>
                        <FormLabel>
                          <Typography variant="h4">
                            {translate('unit')}
                          </Typography>
                        </FormLabel>
                        <Typography>
                          {
                            _.find(
                              SUPPORTED_UNITS,
                              (x) => x.value == currentUnit,
                            )?.name
                          }
                        </Typography>
                      </FormControl>
                    </Grid>
                  </Grid>
                  <Divider sx={{ my: 3 }} />
                  <Stack direction="column" spacing={2}>
                    <Typography sx={{ mb: 3 }} variant="h2">
                      {translate('support')}
                    </Typography>
                    <Stack
                      direction={isSmallScreen ? 'column' : 'row'}
                      spacing={2}
                    >
                      <Button
                        variant="outlined"
                        color="primary"
                        href={
                          currentLang === 'ja'
                            ? '/terms-of-use?lang=ja'
                            : '/terms-of-use?lang=en'
                        }
                        fullWidth={isSmallScreen}
                        sx={{ flex: 1 }}
                      >
                        {translate('open_terms_of_use')}
                      </Button>
                      <Button
                        variant="outlined"
                        color="primary"
                        href={
                          currentLang === 'ja'
                            ? '/privacy-policy?lang=ja'
                            : '/privacy-policy?lang=en'
                        }
                        fullWidth={isSmallScreen}
                        sx={{ flex: 1 }}
                      >
                        {translate('open_privacy_policy')}
                      </Button>
                      {showContactFormButton && contactFormUrl && (
                        <Button
                          variant="outlined"
                          color="primary"
                          href={contactFormUrl}
                          target="_blank"
                          rel="noopener noreferrer"
                          fullWidth={isSmallScreen}
                          sx={{ flex: 1 }}
                        >
                          {translate('open_contact_form')}
                        </Button>
                      )}
                    </Stack>
                  </Stack>
                </Stack>
              </Paper>
            </TabPanel>
            <TabPanel index={TeamTab} value={tabValue}>
              <Paper
                sx={{
                  p: 3,
                  position: 'relative',
                  overflowWrap: 'break-word',
